 3→package e2e
 4→
 5→import (
 6→	"bytes"
 7→	"encoding/json"
 8→	"errors"
 9→	"os/exec"
10→	"testing"
11→)
12→
13→// CommandResult holds the output of a binary invocation.
14→type CommandResult struct {
15→	Stdout   []byte
16→	Stderr   []byte
17→	ExitCode int
18→	Err      error
19→}
20→
21→// AgentRunner invokes an agent binary with subcommands.
22→type AgentRunner struct {
23→	BinaryPath string
24→	Env        []string
25→}
26→
27→// Run executes the agent binary with the given subcommand, args, and optional stdin.
28→func (r *AgentRunner) Run(stdin string, subcommand string, args ...string) CommandResult {
29→	cmdArgs := append([]string{subcommand}, args...)
30→	cmd := exec.Command(r.BinaryPath, cmdArgs...)
31→	cmd.Stdin = bytes.NewBufferString(stdin)
32→	cmd.Env = r.Env
33→
34→	var stdout, stderr bytes.Buffer
35→	cmd.Stdout = &stdout
36→	cmd.Stderr = &stderr
37→
38→	err := cmd.Run()
39→	exitCode := 0
40→	if err != nil {
41→		var exitErr *exec.ExitError
42→		if errors.As(err, &exitErr) {
43→			exitCode = exitErr.ExitCode()
44→		} else {
45→			exitCode = -1
46→		}
47→	}
48→
49→	return CommandResult{
50→		Stdout:   stdout.Bytes(),
51→		Stderr:   stderr.Bytes(),
52→		ExitCode: exitCode,
53→		Err:      err,
54→	}
55→}
56→
57→// RunJSON executes the subcommand and JSON-decodes stdout into dest.
58→func (r *AgentRunner) RunJSON(t *testing.T, dest any, stdin string, subcommand string, args ...string) CommandResult {
59→	t.Helper()
60→	result := r.Run(stdin, subcommand, args...)
61→	if result.ExitCode != 0 {
62→		t.Fatalf("%s %s failed (exit %d): %s", r.BinaryPath, subcommand, result.ExitCode, result.Stderr)
63→	}
64→	if err := json.Unmarshal(result.Stdout, dest); err != nil {
65→		t.Fatalf("failed to decode JSON from %s %s: %v\nstdout: %s", r.BinaryPath, subcommand, err, result.Stdout)
66→	}
67→	return result
68→}
69→
70→// MustSucceed asserts the subcommand exits with code 0.
71→func (r *AgentRunner) MustSucceed(t *testing.T, stdin string, subcommand string, args ...string) CommandResult {
72→	t.Helper()
73→	result := r.Run(stdin, subcommand, args...)
74→	if result.ExitCode != 0 {
75→		t.Fatalf("%s %s: expected exit 0, got %d\nstderr: %s", r.BinaryPath, subcommand, result.ExitCode, result.Stderr)
76→	}
77→	return result
78→}
79→
80→// MustFail asserts the subcommand exits with a non-zero code.
81→func (r *AgentRunner) MustFail(t *testing.T, stdin string, subcommand string, args ...string) CommandResult {
82→	t.Helper()
83→	result := r.Run(stdin, subcommand, args...)
84→	if result.ExitCode == 0 {
85→		t.Fatalf("%s %s: expected non-zero exit, got 0\nstdout: %s", r.BinaryPath, subcommand, result.Stdout)
86→	}
87→	return result
88→}
