 14→
 15→// LifecycleEnv provides a full-lifecycle test environment: a git repo with
 16→// `entire enable` already run, ready for agent prompts and checkpoint assertions.
 17→type LifecycleEnv struct {
 18→	Dir     string   // repo root (temp dir)
 19→	HomeDir string   // isolated HOME
 20→	Env     []string // environment variables for subprocesses
 21→	Agent   string   // agent name (e.g. "kiro")
 22→}
 23→
 24→// NewLifecycleEnv creates a temp git repo, writes an initial commit, and runs
 25→// `entire enable --agent <agentName>`. It also writes .entire/settings.json
 26→// with external_agents enabled.
 27→func NewLifecycleEnv(t *testing.T, agentName string) *LifecycleEnv {
 28→	t.Helper()
 29→
 30→	dir := t.TempDir()
 31→	homeDir := t.TempDir()
 32→
 33→	env := lifecycleEnv(dir, homeDir)
 34→
 35→	le := &LifecycleEnv{
 36→		Dir:     dir,
 37→		HomeDir: homeDir,
 38→		Env:     env,
 39→		Agent:   agentName,
 40→	}
 41→
 42→	// Initialize git repo with a seed commit.
 43→	le.Git(t, "init")
 44→	le.Git(t, "config", "user.email", "test@test.com")
 45→	le.Git(t, "config", "user.name", "Test User")
 46→	le.WriteFile(t, "README.md", "# test repo\n")
 47→	le.Git(t, "add", ".")
 48→	le.Git(t, "commit", "-m", "initial commit")
 49→
 50→	// Write .entire/settings.json with external_agents enabled.
 51→	le.MkdirAll(t, ".entire")
 52→	le.WriteFile(t, ".entire/settings.json", `{"external_agents":true}`)
 53→
 54→	// Run entire enable.
 55→	EntireEnable(t, dir, agentName, env)
 56→
 57→	return le
 58→}
 59→
 60→// Git runs a git command in the repo dir; fails the test on error.
 61→func (le *LifecycleEnv) Git(t *testing.T, args ...string) {
 62→	t.Helper()
 63→	cmd := exec.Command("git", args...)
 64→	cmd.Dir = le.Dir
 65→	cmd.Env = le.Env
 66→	if out, err := cmd.CombinedOutput(); err != nil {
 67→		t.Fatalf("git %s failed: %v\n%s", strings.Join(args, " "), err, out)
 68→	}
 69→}
 70→
 71→// GitOutput runs a git command and returns its combined output.
 72→func (le *LifecycleEnv) GitOutput(t *testing.T, args ...string) string {
 73→	t.Helper()
 74→	cmd := exec.Command("git", args...)
 75→	cmd.Dir = le.Dir
 76→	cmd.Env = le.Env
 77→	out, err := cmd.CombinedOutput()
 78→	if err != nil {
 79→		t.Fatalf("git %s failed: %v\n%s", strings.Join(args, " "), err, out)
 80→	}
 81→	return string(out)
 82→}
