 84→// RunKiroPrompt runs `kiro-cli-chat chat --no-interactive --trust-all-tools --agent entire <prompt>`.
 85→func (le *LifecycleEnv) RunKiroPrompt(t *testing.T, prompt string) error {
 86→	t.Helper()
 87→	bin, err := exec.LookPath("kiro-cli-chat")
 88→	if err != nil {
 89→		t.Fatalf("kiro-cli-chat not in PATH: %v", err)
 90→	}
 91→	cmd := exec.Command(bin, "chat", "--no-interactive", "--trust-all-tools", "--agent", "entire", prompt)
 92→	cmd.Dir = le.Dir
 93→	cmd.Env = le.Env
 94→	out, err := cmd.CombinedOutput()
 95→	if err != nil {
 96→		t.Logf("kiro-cli-chat output:\n%s", out)
 97→		return fmt.Errorf("kiro-cli-chat: %w", err)
 98→	}
 99→	t.Logf("kiro-cli-chat output:\n%s", out)
100→	return nil
101→}
